(()=>{const e=document.getElementById("root");if(e)e.outerHTML="<main class=\"wrap\">\r\n  <div id=\"frontAdminPreviewBar\" class=\"adminPreviewBar\" hidden><div><strong>管理員預覽模式</strong><small id=\"frontPreviewUser\"></small></div><div class=\"btns\"><button id=\"frontBackAdminBtn\" class=\"btn primary\" type=\"button\">返回管理後台</button><button id=\"frontLogoutBtn\" class=\"btn\" type=\"button\">登出</button></div></div>\r\n  <header class=\"top\">\r\n    <button id=\"secretLogo\" class=\"brandLogo\" type=\"button\" aria-label=\"公司標誌\"><img src=\"assets/company-logo.png\" alt=\"環興科技股份有限公司｜SINOTECH ENGINEERING SERVICES, LTD.\"></button>\r\n    <span id=\"frontStatus\" class=\"pill\">載入中</span>\r\n  </header>\r\n  <div id=\"setup\" class=\"setup\">尚未完成 Firebase 設定，請通知系統管理者。</div>\r\n  <div id=\"frontLoading\" class=\"card loading\">正在讀取問卷設定...</div>\r\n  <div id=\"frontContent\" hidden>\r\n    <section class=\"hero\"><h1 id=\"surveyTitle\"></h1><p id=\"surveyDesc\"></p><div id=\"deadline\" class=\"deadline\"></div></section>\r\n    <section id=\"finalFront\" class=\"final\" hidden></section>\r\n    <section id=\"closed\" class=\"closed\" hidden>本次調查目前未開放或已截止，感謝大家。</section>\r\n    <section id=\"done\" class=\"card success\" hidden></section>\r\n    <div id=\"formGrid\" class=\"grid\">\r\n      <section class=\"card formCard\">\r\n        <h2>填寫問卷</h2>\r\n        <div class=\"field\"><label for=\"dept\">部門<span class=\"required\">*</span></label><select id=\"dept\"><option value=\"\">請選擇部門</option></select></div>\r\n        <div class=\"field\"><label for=\"member\">姓名<span class=\"required\">*</span></label><select id=\"member\" disabled><option value=\"\">請先選擇部門</option></select></div>\r\n        <div class=\"field\"><label>參加狀態<span class=\"required\">*</span></label><div class=\"attendanceModes\"><label class=\"mode attend\"><input type=\"radio\" name=\"attendanceMode\" id=\"attendYes\" value=\"attend\"><span><b>可以參加</b><small>繼續選擇可配合的日期</small></span></label><label class=\"mode cannot\"><input type=\"radio\" name=\"attendanceMode\" id=\"cannot\" value=\"cannot\"><span><b>不克參加</b><small>所有候選日期皆無法參加</small></span></label></div></div>\r\n        <div id=\"attendanceDateSection\" class=\"field pending\"><label>可參加日期（可複選）<span class=\"required\">*</span></label><div id=\"dateBox\" class=\"dateBox\"></div></div>\r\n        <div id=\"rankSection\" class=\"field pending\"><label>餐廳選擇順序</label><div id=\"rankGrid\" class=\"rankGrid\"></div></div>\r\n        <div class=\"field\"><label for=\"note\">備註（選填）</label><textarea id=\"note\" maxlength=\"500\"></textarea></div>\r\n        <div class=\"actions\"><button id=\"submitBtn\" class=\"btn primary\" type=\"button\">確認並送出</button><button id=\"clearBtn\" class=\"btn\" type=\"button\">清除內容</button></div>\r\n        <div id=\"submitStatus\" class=\"submitStatus\" role=\"status\" aria-live=\"polite\"></div>\r\n      </section>\r\n      <aside class=\"card information\"><div id=\"frontInstructionsSection\" hidden><h2>填寫說明</h2><div id=\"editPolicyNotice\" class=\"notice\"></div></div><h2>餐廳資訊</h2><div id=\"restInfo\" class=\"restaurants\"></div></aside>\r\n    </div>\r\n  </div>\r\n</main>\r\n<div id=\"toast\" class=\"toast\" role=\"status\" aria-live=\"polite\"></div>";})();